"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[5302],{8680:e=>{e.exports=JSON.parse('{"functions":[{"name":"Enabled","desc":"Enables or disables the 6DOF aerodynamics system for this cast.\\nWhen `false` (the default), no 6DOF code runs and all other fields are ignored.\\n\\nDefault: `false`","params":[{"name":"value","desc":"","lua_type":"boolean"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1016,"path":"docs/SubBuilders.lua"}},{"name":"LiftCoefficientSlope","desc":"dCL/d\u03b1 \u2014 lift coefficient slope. Scales aerodynamic lift with angle of attack.\\nTypical range: `1.0`\u2013`4.0`. `0` disables lift.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1027,"path":"docs/SubBuilders.lua"}},{"name":"PitchingMomentSlope","desc":"dCm/d\u03b1 \u2014 pitching moment slope. Negative values produce a statically stable\\nrestoring torque (the bullet noses back toward velocity). Zero = neutrally stable.\\nTypical range: `-1.0` to `-0.1`.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1039,"path":"docs/SubBuilders.lua"}},{"name":"PitchDampingCoeff","desc":"Cmq \u2014 pitch/yaw damping coefficient. Damps wobble and coning motion.\\nTypical range: `0.005`\u2013`0.05`. `0` = no damping.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1050,"path":"docs/SubBuilders.lua"}},{"name":"RollDampingCoeff","desc":"Clp \u2014 roll damping coefficient. Controls how quickly axial spin decays.\\nTypical range: `0.001`\u2013`0.02`. `0` = no spin decay.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1061,"path":"docs/SubBuilders.lua"}},{"name":"AoADragFactor","desc":"sin\xb2\u03b1 drag multiplier. Adds extra drag proportional to angle of attack squared.\\n`3.0` triples drag at 90\xb0 AoA. `0` = no AoA-dependent drag.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1072,"path":"docs/SubBuilders.lua"}},{"name":"ReferenceArea","desc":"Reference cross-sectional area in studs\xb2. Scales all aerodynamic forces.\\nTypical value for a rifle bullet: `0.005`\u2013`0.02`.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1083,"path":"docs/SubBuilders.lua"}},{"name":"ReferenceLength","desc":"Reference length (caliber) in studs. Used for pitching moment and damping torques.\\nTypical value for a rifle bullet: `0.03`\u2013`0.1`.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1094,"path":"docs/SubBuilders.lua"}},{"name":"AirDensity","desc":"Air density in kg/m\xb3. Scales all aerodynamic forces.\\nUse lower values for high-altitude simulation.\\n\\nDefault: `1.225` (sea level)","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1105,"path":"docs/SubBuilders.lua"}},{"name":"MomentOfInertia","desc":"Transverse moment of inertia. Governs pitch/yaw angular acceleration from aerodynamic torques.\\nTypical value for a rifle bullet: `0.0005`\u2013`0.005`.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1116,"path":"docs/SubBuilders.lua"}},{"name":"SpinMOI","desc":"Axial (spin) moment of inertia. Required for gyroscopic precession.\\nTypical value for a rifle bullet: `0.0001`\u2013`0.001`. `0` disables precession.\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1127,"path":"docs/SubBuilders.lua"}},{"name":"MaxAngularSpeed","desc":"Angular speed ceiling in rad/s. Clamps the angular velocity magnitude each step\\nto prevent divergence under extreme torques.\\n\\nDefault: `~628` rad/s (\u22486000 RPM)","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1138,"path":"docs/SubBuilders.lua"}},{"name":"InitialOrientation","desc":"Initial body-frame orientation as a `CFrame`. When `nil`, the orientation is\\nseeded from a velocity look-at at fire time.\\n\\nDefault: `nil`","params":[{"name":"value","desc":"","lua_type":"CFrame?"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1149,"path":"docs/SubBuilders.lua"}},{"name":"InitialAngularVelocity","desc":"Initial angular velocity in rad/s (world frame). When `nil`, seeded from the\\nMagnus `SpinVector` if one is set, otherwise zero.\\n\\nDefault: `nil`","params":[{"name":"value","desc":"","lua_type":"Vector3?"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1160,"path":"docs/SubBuilders.lua"}},{"name":"CLAlphaMachTable","desc":"Mach-indexed CL\u03b1 table. Overrides [SixDOFBuilder:LiftCoefficientSlope] when set.\\nUseful for transonic/supersonic lift drop-off modelling.\\n\\nTable format: `{ {mach, cl_alpha}, ... }` sorted ascending by Mach number.\\n\\nDefault: `nil` (flat scalar used)","params":[{"name":"value","desc":"","lua_type":"{{number}}"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1173,"path":"docs/SubBuilders.lua"}},{"name":"CmAlphaMachTable","desc":"Mach-indexed Cm\u03b1 table. Overrides [SixDOFBuilder:PitchingMomentSlope] when set.\\nUseful for modelling reduced static stability at transonic speeds.\\n\\nTable format: `{ {mach, cm_alpha}, ... }` sorted ascending by Mach number.\\n\\nDefault: `nil` (flat scalar used)","params":[{"name":"value","desc":"","lua_type":"{{number}}"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1186,"path":"docs/SubBuilders.lua"}},{"name":"CmqMachTable","desc":"Mach-indexed Cmq table. Overrides [SixDOFBuilder:PitchDampingCoeff] when set.\\nAllows pitch/yaw damping to vary with Mach number.\\n\\nTable format: `{ {mach, cmq}, ... }` sorted ascending by Mach number.\\n\\nDefault: `nil` (flat scalar used)","params":[{"name":"value","desc":"","lua_type":"{{number}}"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1199,"path":"docs/SubBuilders.lua"}},{"name":"ClpMachTable","desc":"Mach-indexed Clp table. Overrides [SixDOFBuilder:RollDampingCoeff] when set.\\nAllows spin-decay rate to vary with Mach number.\\n\\nTable format: `{ {mach, clp}, ... }` sorted ascending by Mach number.\\n\\nDefault: `nil` (flat scalar used)","params":[{"name":"value","desc":"","lua_type":"{{number}}"}],"returns":[{"desc":"","lua_type":"SixDOFBuilder"}],"function_type":"method","source":{"line":1212,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":1218,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"SixDOFBuilder","desc":"Sub-builder for 6DOF aerodynamic physics configuration. Opened via [BehaviorBuilder:SixDOF].\\nCall `:Done()` to return to the root [BehaviorBuilder].\\n\\n:::caution BulletMass required\\nWhen 6DOF is enabled, `BulletMass` must be set via `:Physics():BulletMass()`.\\n`:Build()` returns `nil` if it is zero or unset \u2014 mass is required to convert\\naerodynamic force vectors into accelerations.\\n:::","source":{"line":1005,"path":"docs/SubBuilders.lua"}}')}}]);